CREATE VIRTUAL TABLE catalog_search USING fts5(
  item_id UNINDEXED,
  kind UNINDEXED,
  document_version UNINDEXED,
  fingerprint UNINDEXED,
  slug,
  title,
  description,
  facets,
  latin_slug,
  latin_title,
  latin_description,
  latin_facets,
  tokenize = 'unicode61',
  prefix = '2 3'
);
