CREATE VIEW catalog_search_diagnostics AS
SELECT
  (SELECT count(*) FROM catalog_search_documents) AS canonical_count,
  (SELECT count(*) FROM catalog_search) AS projection_count,
  (SELECT count(*) FROM catalog_search_documents expected WHERE NOT EXISTS (SELECT 1 FROM catalog_search actual WHERE actual.item_id = expected.item_id)) AS missing_count,
  (SELECT count(*) FROM catalog_search actual WHERE NOT EXISTS (SELECT 1 FROM catalog_search_documents expected WHERE expected.item_id = actual.item_id)) AS orphan_count,
  (SELECT count(*) FROM (SELECT item_id FROM catalog_search GROUP BY item_id HAVING count(*) > 1)) AS duplicate_count,
  (SELECT count(*) FROM catalog_search_documents expected JOIN catalog_search actual ON actual.item_id = expected.item_id WHERE actual.document_version IS NOT expected.document_version OR actual.fingerprint IS NOT expected.fingerprint OR actual.kind IS NOT expected.kind OR actual.slug IS NOT expected.slug OR actual.title IS NOT expected.title OR actual.description IS NOT expected.description OR actual.facets IS NOT expected.facets OR actual.latin_slug IS NOT expected.latin_slug OR actual.latin_title IS NOT expected.latin_title OR actual.latin_description IS NOT expected.latin_description OR actual.latin_facets IS NOT expected.latin_facets) AS mismatched_count;
