CREATE TRIGGER catalog_search_refresh_item AFTER INSERT ON catalog_search_refresh BEGIN
  DELETE FROM catalog_search WHERE item_id = NEW.item_id;
  INSERT INTO catalog_search(item_id, kind, document_version, fingerprint, slug, title, description, facets, latin_slug, latin_title, latin_description, latin_facets) SELECT item_id, kind, document_version, fingerprint, slug, title, description, facets, latin_slug, latin_title, latin_description, latin_facets FROM catalog_search_documents WHERE item_id = NEW.item_id;
  DELETE FROM catalog_search_refresh WHERE item_id = NEW.item_id;
END;
